import { parseEther, parseUnits, formatUnits, createPublicClient, http, fallback } from 'viem'
import { mainnet } from 'viem/chains'
import type { WalletClient, PublicClient } from 'viem'
import { ROUTERS } from './wagmi'
import { BYTECODES } from './bytecodes'

// ── Payment constants ─────────────────────────────────────────────────────────
export const TREASURY     = '0xA7d617117887b3cAf2C93B07ceD3081Ee9F8F63a' as `0x${string}` // REPLACE with your wallet
export const BLIN_ADDRESS = '0xaEFB54306240502c5421Be478fa16aACfA9698A2' as `0x${string}`
export const BLIN_CHAIN_ID = 1 // $BLIN is on Ethereum mainnet

// Dedicated Ethereum mainnet client for all BLIN reads
// This is chain-agnostic — it always hits mainnet regardless of the user's connected chain
const ethMainnetClient = createPublicClient({
  chain: mainnet,
  transport: fallback([
    http('https://eth.llamarpc.com'),
    http('https://rpc.ankr.com/eth'),
    http('https://1rpc.io/eth'),
    http('https://ethereum.publicnode.com'),
  ]),
})

export const TIER_PRICES = {
  starter: { blin: parseUnits('50000',  18), native: parseEther('0.05'),  label: '$49'  },
  pro:     { blin: parseUnits('150000', 18), native: parseEther('0.15'),  label: '$149' },
  elite:   { blin: parseUnits('400000', 18), native: parseEther('0.40'),  label: '$399' },
}

// ERC-20 ABI (minimal)
export const ERC20_ABI = [
  {
    name: 'transfer',
    type: 'function',
    stateMutability: 'nonpayable',
    inputs:  [{ name: 'to', type: 'address' }, { name: 'amount', type: 'uint256' }],
    outputs: [{ type: 'bool' }],
  },
  {
    name: 'balanceOf',
    type: 'function',
    stateMutability: 'view',
    inputs:  [{ name: 'account', type: 'address' }],
    outputs: [{ type: 'uint256' }],
  },
] as const

// ── Pay with BLIN ─────────────────────────────────────────────────────────────
// $BLIN lives on Ethereum mainnet. We:
//   1. Read balance via a dedicated mainnet public client (not the user's active chain)
//   2. Ask the wallet to switch to mainnet before sending the transfer
//   3. Wait for receipt on mainnet
export async function payWithBLIN(
  tier: string,
  walletClient: WalletClient,
  _publicClient: PublicClient, // kept for API compat, but we use ethMainnetClient for reads
  onStatus: (s: string) => void,
  overrideBlinAmount?: bigint,  // explicit amount from Supabase dynamic pricing
): Promise<string> {
  const fallback = TIER_PRICES[tier as keyof typeof TIER_PRICES]
  const blinAmount = overrideBlinAmount ?? fallback?.blin
  if (!blinAmount) throw new Error('Unknown tier')
  // Build a price-like object so the rest of the function stays unchanged
  const price = { blin: blinAmount }

  const [account] = await walletClient.getAddresses()

  // 1. Check balance on Ethereum mainnet directly
  onStatus('Checking BLIN balance on Ethereum mainnet…')
  let bal: bigint
  try {
    bal = await ethMainnetClient.readContract({
      address: BLIN_ADDRESS,
      abi: ERC20_ABI,
      functionName: 'balanceOf',
      args: [account],
    }) as bigint
  } catch (e: any) {
    throw new Error(`Failed to read BLIN balance. Make sure you are using an Ethereum-compatible wallet.\n${e.message}`)
  }

  if (bal < price.blin) {
    throw new Error(
      `Insufficient BLIN balance. You have ${formatUnits(bal, 18)} BLIN but need ${formatUnits(price.blin, 18)} BLIN.\n` +
      `$BLIN contract: ${BLIN_ADDRESS} (Ethereum mainnet)`
    )
  }

  // 2. Switch wallet to Ethereum mainnet for the transfer
  onStatus('Switching wallet to Ethereum mainnet for BLIN transfer…')
  try {
    await walletClient.switchChain({ id: mainnet.id })
  } catch (e: any) {
    // Some wallets throw if already on the right chain — that's fine
    if (!e.message?.includes('already') && !e.message?.includes('same')) {
      throw new Error(`Could not switch to Ethereum mainnet: ${e.message}`)
    }
  }

  // 3. Send BLIN transfer on mainnet
  onStatus('Sending BLIN payment…')
  const hash = await walletClient.writeContract({
    address: BLIN_ADDRESS,
    abi: ERC20_ABI,
    functionName: 'transfer',
    args: [TREASURY, price.blin],
    account,
    chain: mainnet,
  })

  // 4. Wait for confirmation on mainnet
  onStatus('Waiting for confirmation on Ethereum mainnet…')
  await ethMainnetClient.waitForTransactionReceipt({ hash })
  return hash
}

// ── Pay with native (ETH/BNB on user's connected chain) ───────────────────────
export async function payWithNative(
  tier: string,
  walletClient: WalletClient,
  publicClient: PublicClient,
  onStatus: (s: string) => void,
  overrideNativeAmount?: bigint,  // explicit amount from Supabase dynamic pricing
): Promise<string> {
  const fallback = TIER_PRICES[tier as keyof typeof TIER_PRICES]
  const nativeAmount = overrideNativeAmount ?? fallback?.native
  if (!nativeAmount) throw new Error('Unknown tier')
  const [account] = await walletClient.getAddresses()

  onStatus('Sending payment…')
  const hash = await walletClient.sendTransaction({
    to: TREASURY,
    value: nativeAmount,
    account,
    chain: walletClient.chain!,
  })

  onStatus('Waiting for confirmation…')
  await publicClient.waitForTransactionReceipt({ hash })
  return hash
}

// ── Direct deploy: bytecode + initialize() ───────────────────────────────────
// No pre-deployed factory needed. Each user deploys their own full contract.
// Flow: (1) deploy bytecode → get address  (2) call initialize() with params
// Two wallet confirmations; the UI shows progress for each step.

const DEAD = '0x000000000000000000000000000000000000dEaD' as `0x${string}`

const STANDARD_INIT_ABI = [
  {
    name: 'initialize', type: 'function', stateMutability: 'nonpayable',
    inputs: [
      { name: 'name_',        type: 'string'  },
      { name: 'symbol_',      type: 'string'  },
      { name: 'decimals_',    type: 'uint8'   },
      { name: 'totalSupply_', type: 'uint256' },
      { name: 'owner_',       type: 'address' },
    ],
    outputs: [],
  },
] as const

// FatTax & FatDeflationary: marketingPercent is field 0
const TAX_INIT_ABI = [
  {
    name: 'initialize', type: 'function', stateMutability: 'nonpayable',
    inputs: [
      { name: 'name_',        type: 'string'  },
      { name: 'symbol_',      type: 'string'  },
      { name: 'decimals_',    type: 'uint8'   },
      { name: 'totalSupply_', type: 'uint256' },
      { name: 'owner_',       type: 'address' },
      { name: 'taxBehavior_', type: 'tuple', components: [
        { name: 'taxOnTransfer', type: 'bool'    },
        { name: 'taxOnBuy',      type: 'bool'    },
        { name: 'taxOnSell',     type: 'bool'    },
        { name: 'transferTax',   type: 'uint256' },
        { name: 'buyTax',        type: 'uint256' },
        { name: 'sellTax',       type: 'uint256' },
      ]},
      { name: 'taxDistribution_', type: 'tuple', components: [
        { name: 'marketingPercent', type: 'uint256' },
        { name: 'liquidityPercent', type: 'uint256' },
        { name: 'teamPercent',      type: 'uint256' },
        { name: 'buybackPercent',   type: 'uint256' },
        { name: 'burnPercent',      type: 'uint256' },
        { name: 'marketingWallet',  type: 'address' },
        { name: 'teamWallet',       type: 'address' },
        { name: 'buybackWallet',    type: 'address' },
      ]},
      { name: 'dexRouter_', type: 'address' },
    ],
    outputs: [],
  },
] as const

// FatReflection: reflectionPercent is field 0 (different struct layout)
const REFLECTION_INIT_ABI = [
  {
    name: 'initialize', type: 'function', stateMutability: 'nonpayable',
    inputs: [
      { name: 'name_',        type: 'string'  },
      { name: 'symbol_',      type: 'string'  },
      { name: 'decimals_',    type: 'uint8'   },
      { name: 'totalSupply_', type: 'uint256' },
      { name: 'owner_',       type: 'address' },
      { name: 'taxBehavior_', type: 'tuple', components: [
        { name: 'taxOnTransfer', type: 'bool'    },
        { name: 'taxOnBuy',      type: 'bool'    },
        { name: 'taxOnSell',     type: 'bool'    },
        { name: 'transferTax',   type: 'uint256' },
        { name: 'buyTax',        type: 'uint256' },
        { name: 'sellTax',       type: 'uint256' },
      ]},
      { name: 'taxDistribution_', type: 'tuple', components: [
        { name: 'reflectionPercent', type: 'uint256' }, // ← field 0 in FatReflection
        { name: 'marketingPercent',  type: 'uint256' },
        { name: 'liquidityPercent',  type: 'uint256' },
        { name: 'teamPercent',       type: 'uint256' },
        { name: 'buybackPercent',    type: 'uint256' },
        { name: 'marketingWallet',   type: 'address' },
        { name: 'teamWallet',        type: 'address' },
        { name: 'buybackWallet',     type: 'address' },
      ]},
      { name: 'dexRouter_', type: 'address' },
    ],
    outputs: [],
  },
] as const

export type DeployArgs = {
  name: string; symbol: string; decimals: number; totalSupply: string
  tokenType: 'standard' | 'tax' | 'deflationary' | 'reflection'
  fundAddress: `0x${string}`
  receiveAddress: `0x${string}`
  teamWallet: `0x${string}`
  buybackWallet: `0x${string}`
  taxOnTransfer: boolean; taxOnBuy: boolean; taxOnSell: boolean
  buyTax: number; sellTax: number; transferTax: number
  mktPct: number; lpPct: number; teamPct: number; buybackPct: number; burnPct: number
  chainId: number
}

function extractRevert(e: unknown): string {
  const msg = (e as any)?.message || String(e)
  const reason = msg.match(/reverted with reason string '(.+?)'/)?.[1]
  if (reason) return reason
  const custom = msg.match(/reverted with the following reason:\s*(.+?)(?:\n|$)/i)?.[1]
  if (custom) return custom.trim()
  const details = msg.match(/Details:\s*(.+?)(?:\n|$)/)?.[1]
  if (details) return details.trim()
  const revert = msg.match(/execution reverted:?\s*(.+?)(?:\n|$)/i)?.[1]
  if (revert) return revert.trim()
  return msg.slice(0, 300)
}

export async function deployToken(
  args: DeployArgs,
  walletClient: WalletClient,
  publicClient: PublicClient,
  onStatus: (s: string) => void
): Promise<{ contractAddress: string; txHash: string }> {
  const [account] = await walletClient.getAddresses()
  const dec0 = 10n ** BigInt(args.decimals)
  const totalSupplyWei = BigInt(args.totalSupply) * dec0

  // ── Pre-flight validation (before any wallet interaction) ─────────────────
  const isRealAddr = (a: string) => !!a && a.length >= 42 && a.toLowerCase() !== '0x0000000000000000000000000000000000000000'
  const mktWallet  = (isRealAddr(args.fundAddress)   ? args.fundAddress   : DEAD) as `0x${string}`
  const teamWallet = (isRealAddr(args.teamWallet)    ? args.teamWallet    : DEAD) as `0x${string}`
  const bbWallet   = (isRealAddr(args.buybackWallet) ? args.buybackWallet : DEAD) as `0x${string}`
  const dexRouter  = (ROUTERS[args.chainId] ?? DEAD) as `0x${string}`

  if (!args.name.trim())   throw new Error('Token name is required. Go back to Step 2.')
  if (!args.symbol.trim()) throw new Error('Token symbol is required. Go back to Step 2.')

  if (args.tokenType !== 'standard') {
    const total = args.mktPct + args.lpPct + args.teamPct + args.buybackPct + args.burnPct
    if (total !== 100)
      throw new Error(`Tax distribution must sum to 100% (currently ${total}%). Go back to Step 3 and adjust the sliders.`)
    if (args.buyTax > 2500)      throw new Error(`Buy tax exceeds 25% max (${args.buyTax} bps). Go back to Step 3.`)
    if (args.sellTax > 2500)     throw new Error(`Sell tax exceeds 25% max (${args.sellTax} bps). Go back to Step 3.`)
    if (args.transferTax > 2500) throw new Error(`Transfer tax exceeds 25% max (${args.transferTax} bps). Go back to Step 3.`)
    if (args.mktPct > 0 && !isRealAddr(args.fundAddress))
      throw new Error('Marketing wallet address is required when marketing % > 0. Go back to Step 2.')
    if (args.teamPct > 0 && !isRealAddr(args.teamWallet))
      throw new Error('Team wallet address is required when team % > 0. Set it in Step 2 or set team % to 0.')
    if (args.buybackPct > 0 && !isRealAddr(args.buybackWallet))
      throw new Error('Buyback wallet address is required when buyback % > 0. Set it in Step 2 or set buyback % to 0.')
  }

  // ── Build ABI + init args now (needed for estimateContractGas later) ─────
  const taxBehavior = {
    taxOnTransfer: args.taxOnTransfer,
    taxOnBuy:      args.taxOnBuy,
    taxOnSell:     args.taxOnSell,
    transferTax:   BigInt(args.transferTax),
    buyTax:        BigInt(args.buyTax),
    sellTax:       BigInt(args.sellTax),
  }

  let initAbi: typeof STANDARD_INIT_ABI | typeof TAX_INIT_ABI | typeof REFLECTION_INIT_ABI
  let initArgs: readonly unknown[]

  if (args.tokenType === 'standard') {
    initAbi  = STANDARD_INIT_ABI
    initArgs = [args.name, args.symbol, args.decimals, totalSupplyWei, account] as const
  } else if (args.tokenType === 'reflection') {
    const taxDistribution = {
      reflectionPercent: BigInt(args.burnPct   * 100),
      marketingPercent:  BigInt(args.mktPct    * 100),
      liquidityPercent:  BigInt(args.lpPct     * 100),
      teamPercent:       BigInt(args.teamPct   * 100),
      buybackPercent:    BigInt(args.buybackPct * 100),
      marketingWallet:   mktWallet,
      teamWallet,
      buybackWallet:     bbWallet,
    }
    initAbi  = REFLECTION_INIT_ABI
    initArgs = [args.name, args.symbol, args.decimals, totalSupplyWei, account, taxBehavior, taxDistribution, dexRouter] as const
  } else {
    // tax + deflationary: same struct layout (burnPercent / deflationPercent both sit at slot 4)
    const taxDistribution = {
      marketingPercent: BigInt(args.mktPct     * 100),
      liquidityPercent: BigInt(args.lpPct      * 100),
      teamPercent:      BigInt(args.teamPct    * 100),
      buybackPercent:   BigInt(args.buybackPct * 100),
      burnPercent:      BigInt(args.burnPct    * 100),
      marketingWallet:  mktWallet,
      teamWallet,
      buybackWallet:    bbWallet,
    }
    initAbi  = TAX_INIT_ABI
    initArgs = [args.name, args.symbol, args.decimals, totalSupplyWei, account, taxBehavior, taxDistribution, dexRouter] as const
  }

  // ── Select bytecode ────────────────────────────────────────────────────────
  const bytecodeMap = {
    standard:     BYTECODES.FatStandard,
    tax:          BYTECODES.FatTax,
    deflationary: BYTECODES.FatDeflationary,
    reflection:   BYTECODES.FatReflection,
  } as const
  const bytecode = bytecodeMap[args.tokenType]
  const typeLabel = args.tokenType.charAt(0).toUpperCase() + args.tokenType.slice(1)

  // ── Step 1: estimate + deploy bytecode ────────────────────────────────────
  onStatus(`Step 1 of 2 — Simulating deployment…`)
  let deployGas: bigint
  try {
    deployGas = await publicClient.estimateGas({ data: bytecode, account })
  } catch (e) {
    throw new Error(`Deployment simulation failed: ${extractRevert(e)}`)
  }

  onStatus(`Step 1 of 2 — Deploying Fat${typeLabel} contract… confirm in wallet`)
  const deployHash = await walletClient.sendTransaction({
    data: bytecode,
    account,
    gas: deployGas * 13n / 10n, // 30% buffer to avoid edge-case OOG
    chain: walletClient.chain!,
  })

  onStatus('Step 1 of 2 — Waiting for deployment confirmation…')
  const deployReceipt = await publicClient.waitForTransactionReceipt({ hash: deployHash })

  const contractAddress = deployReceipt.contractAddress
  if (!contractAddress) throw new Error('Deploy failed — no contract address in receipt')

  // ── Step 2: estimate + initialize ─────────────────────────────────────────
  onStatus(`Step 2 of 2 — Simulating initialization…`)
  let initGas: bigint
  try {
    initGas = await publicClient.estimateContractGas({
      address: contractAddress,
      abi:     initAbi as any,
      functionName: 'initialize',
      args:    initArgs as any,
      account,
    })
  } catch (e) {
    throw new Error(`Initialization simulation failed: ${extractRevert(e)}`)
  }

  onStatus(`Step 2 of 2 — Initializing token… confirm in wallet`)
  const initHash = await walletClient.writeContract({
    address: contractAddress,
    abi:     initAbi as any,
    functionName: 'initialize',
    args:    initArgs as any,
    account,
    gas:   initGas * 13n / 10n,
    chain: walletClient.chain!,
  })

  onStatus('Step 2 of 2 — Waiting for initialization confirmation…')
  await publicClient.waitForTransactionReceipt({ hash: initHash })

  return { contractAddress, txHash: deployHash }
}

// ── LEGACY: keep FAT_BYTECODE export so old imports don't break immediately ───
// Remove once all step components are updated to use deployToken().
export const FAT_BYTECODE = "" as `0x${string}`


// ── Constructor param summary (for Step5Review) ───────────────────────────────
export function generateParams(cfg: any, chainId: number): string {
  const pct = (n: number) => `${n}% (${n * 100} bps)`
  const bps = (n: number) => `${n} bps (${(n / 100).toFixed(2)}%)`
  const burnLabel = cfg.tokenType === 'reflection' ? 'reflection' : 'burn'
  const router = ROUTERS[chainId] ?? '(unsupported chain)'
  return `// Token: ${(cfg.tokenType ?? 'tax').toUpperCase()}
name        = "${cfg.name || 'My Token'}"
symbol      = "${cfg.symbol || 'MTK'}"
decimals    = ${cfg.decimals}
totalSupply = ${cfg.totalSupply}

// Addresses
marketingWallet = "${cfg.fundAddress || '0x...'}"
receiveAddress  = "${cfg.receiveAddress || '0x...'}"
teamWallet      = "${cfg.teamWallet || '(none — uses dead address)'}"
buybackWallet   = "${cfg.buybackWallet || '(none — uses dead address)'}"${cfg.tokenType === 'reflection' ? `\nrewardToken     = "${cfg.rewardToken || '(defaults to WBNB/WETH)'}"` : ''}

// Tax behavior
taxOnBuy       = ${cfg.taxOnBuy}  →  ${bps(cfg.buyTax ?? 0)}
taxOnSell      = ${cfg.taxOnSell}  →  ${bps(cfg.sellTax ?? 0)}
taxOnTransfer  = ${cfg.taxOnTransfer}  →  ${bps(cfg.transferTax ?? 0)}

// Tax distribution (must sum to 100%)
marketing  = ${pct(cfg.mktPct ?? 0)}
liquidity  = ${pct(cfg.lpPct ?? 0)}
team       = ${pct(cfg.teamPct ?? 0)}
buyback    = ${pct(cfg.buybackPct ?? 0)}
${burnLabel}      = ${pct(cfg.burnPct ?? 0)}

// Network
dexRouter = "${router}" (chain ${chainId})`
}
